import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        for i in range(1, n + 1):
            out.append(' '.join(str(j) for j in range(1, i + 1)) + ' ')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

